/**
 * Regression guard for local-only short-lived sub-agent branch prompts.
 *
 * Scoped worker roles must not instruct team/delegated agents to publish their
 * ephemeral branches by default. The team lead must merge those branches from
 * local refs/worktrees instead of remote member refs.
 */
import test from "node:test";
import assert from "node:assert/strict";
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, "..");

function rolePrompt(role: string): string {
	const raw = fs.readFileSync(path.join(repoRoot, "defaults", "roles", `${role}.yaml`), "utf8");
	const match = raw.match(/^promptTemplate:\s*\|-?\s*\r?\n([\s\S]*)$/m);
	assert.ok(match, `${role} must define a block promptTemplate`);
	return match[1];
}

const scopedWorkerRoles = ["coder", "test-engineer", "docs-writer"];

for (const role of scopedWorkerRoles) {
	test(`default ${role} prompt keeps short-lived branches local-only`, () => {
		const prompt = rolePrompt(role);

		assert.match(prompt, /short-lived branches are local-only by default/i);
		assert.match(prompt, /Persistent local worktrees are the durability mechanism/i);
		assert.match(prompt, /requested by the user/i);
		assert.match(prompt, /required by a workflow/i);
		assert.match(prompt, /remote handoff/i);
		assert.match(prompt, /cross-machine\/container handoff/i);
		assert.match(prompt, /final publication flow/i);
		assert.match(prompt, /Verify your current branch and `git status`/i);
		assert.match(prompt, /Only fetch\/pull if an upstream exists/i);

		assert.doesNotMatch(prompt, /\bgit pull\b\s+to get the latest on your branch/i, `${role} must not require unconditional worker git pull`);
		assert.doesNotMatch(prompt, /^\s*1\.\s*`git pull`/im, `${role} must not start local-only workflow with unconditional git pull`);
		assert.doesNotMatch(prompt, /\bgit push\b/i, `${role} must not require worker git push`);
		assert.doesNotMatch(prompt, /branch is pushed/i, `${role} must not require a pushed branch for DoD`);
		assert.doesNotMatch(prompt, /safety net for crash recovery/i, `${role} must not cite remote pushes as durability`);
		assert.doesNotMatch(prompt, /job ends when your branch is pushed/i, `${role} gates text must not require branch publication`);
		assert.doesNotMatch(prompt, /Push your branch when done/i, `${role} must not tell workers to push by default`);
	});
}

test("team lead prompt merges member branches locally, not from remote member refs", () => {
	const prompt = rolePrompt("team-lead");

	assert.match(prompt, /merge member branches locally with `git merge <task\.branch>`/i);
	assert.match(prompt, /git cherry-pick <task\.baseSha>\.\.<task\.headSha>/);
	assert.match(prompt, /No remote fetch needed/i);
	assert.match(prompt, /short-lived branches are local-only by default/i);

	assert.doesNotMatch(prompt, /origin\/<member-branch>/i);
	assert.doesNotMatch(prompt, /git fetch origin\s*&&\s*git merge origin/i);
	assert.doesNotMatch(prompt, /agents push to origin as a safety net/i);
	assert.doesNotMatch(prompt, /safety net for crash recovery/i);
});
